package api

import (
	"errors"
	"fmt"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime/schema"
)

const (
	resourceGroup               = "agentcube.volcano.sh"
	sessionResourceName         = "sessions"
	agentRuntimeResourceName    = "agentruntimes"
	codeInterpreterResourceName = "codeinterpreters"
)

var (
	ErrAgentRuntimeNotFound    = errors.New("agent runtime not found")
	ErrCodeInterpreterNotFound = errors.New("code interpreter not found")
	ErrTemplateMissing         = errors.New("resource has no pod template")
	ErrPublicKeyMissing        = errors.New("public key not yet loaded from Router Secret")
)

type APIStatus interface {
	Status() metav1.Status
}

func NewSessionNotFoundError(sessionID string) error {
	return &metav1.StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    404,
			Reason:  metav1.StatusReasonNotFound,
			Message: fmt.Sprintf("session %q not found", sessionID),
			Details: &metav1.StatusDetails{
				Group: resourceGroup,
				Kind:  sessionResourceName,
				Name:  sessionID,
			},
		},
	}
}

func NewSandboxTemplateNotFoundError(namespace, name, kind string) error {
	var gr string
	if kind == "CodeInterpreter" {
		gr = codeInterpreterResourceName
	} else {
		gr = agentRuntimeResourceName
	}
	return &metav1.StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    404,
			Reason:  metav1.StatusReasonNotFound,
			Message: fmt.Sprintf("sandbox template %s/%s not found", namespace, name),
			Details: &metav1.StatusDetails{
				Group: resourceGroup,
				Kind:  gr,
				Name:  name,
			},
		},
	}
}

func NewUpstreamUnavailableError(err error) error {
	return &metav1.StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    502,
			Reason:  metav1.StatusReasonServiceUnavailable,
			Message: fmt.Sprintf("upstream unavailable: %v", err),
		},
	}
}

func NewInternalError(err error) error {
	return &metav1.StatusError{
		ErrStatus: metav1.Status{
			Status:  metav1.StatusFailure,
			Code:    500,
			Reason:  metav1.StatusReasonInternalError,
			Message: "internal server error",
		},
	}
}

func GRForResource(resource string) schema.GroupResource {
	return schema.GroupResource{
		Group:    resourceGroup,
		Resource: resource,
	}
}

