		return nil, errors.New("VALKEY_PASSWORD is required unless VALKEY_PASSWORD_REQUIRED=false")
	}

	opts := &valkey.ClientOption{
		InitAddress: strings.Split(valkeyAddr, ","),
		Password:    valkeyPassword,
	}

	if val, err := strconv.ParseBool(os.Getenv("VALKEY_DISABLE_CACHE")); err == nil && val {
		opts.DisableCache = true
	}
	if val, err := strconv.ParseBool(os.Getenv("VALKEY_FORCE_SINGLE")); err == nil && val {
		opts.ForceSingleClient = true
	}

	klog.InfoS("Valkey options", "initAddress", opts.InitAddress, "disableCache", opts.DisableCache, "forceSingle", opts.ForceSingleClient)
	return opts, nil
}

func (s *valkeyStore) sessionKey(sessionID string) string {
	return s.sessionPrefix + sessionID
}

func (s *valkeyStore) Ping(ctx context.Context) error {
	result, err := s.cli.Do(ctx, s.cli.B().Ping().Build()).ToString()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (s *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := s.sessionKey(sessionID)
	result, err := s.cli.Do(ctx, s.cli.B().Get().Key(key).Build()).AsBytes()
	if err != nil {
		if valkey.IsValkeyNil(err) {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var info types.SandboxInfo
	if err := json.Unmarshal(result, &info); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox info: %w", err)
	}

	return &info, nil
}

func (s *valkeyStore) StoreSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return errors.New("sandbox is nil")
	}
	if sandboxStore.ExpiresAt.IsZero() {
		return errors.New("ExpiresAt is required")
	}

	key := s.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox info: %w", err)
	}

	expiryScore := float64(sandboxStore.ExpiresAt.Unix())
	activityScore := float64(time.Now().Unix())

	results := s.cli.DoMulti(ctx,
		s.cli.B().Setnx().Key(key).Value(string(data)).Build(),
		s.cli.B().Zadd().Key(s.expiryIndexKey).ScoreMember().ScoreMember(expiryScore, sandboxStore.SessionID).Build(),
		s.cli.B().Zadd().Key(s.lastActivityIndexKey).ScoreMember().ScoreMember(activityScore, sandboxStore.SessionID).Build(),
	)

	for _, res := range results {
		if err := res.Error(); err != nil {
			return err
		}
	}

	return nil
}

func (s *valkeyStore) UpdateSandbox(ctx context.Context, sandboxStore *types.SandboxInfo) error {
	if sandboxStore == nil {
		return errors.New("sandbox is nil")
	}

	key := s.sessionKey(sandboxStore.SessionID)
	data, err := json.Marshal(sandboxStore)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox info: %w", err)
	}

	result, err := s.cli.Do(ctx, s.cli.B().Set().Key(key).Value(string(data)).Xx().Build()).ToString()
	if err != nil {
		return err
	}
	if result != "OK" {
		return errors.New("key not exists")
	}

	return nil
}

func (s *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := s.sessionKey(sessionID)

	s.cli.DoMulti(ctx,
		s.cli.B().Del().Key(key).Build(),
		s.cli.B().Zrem().Key(s.expiryIndexKey).Member(sessionID).Build(),
		s.cli.B().Zrem().Key(s.lastActivityIndexKey).Member(sessionID).Build(),
	)
	return nil
}

func (s *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	result, err := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.expiryIndexKey).
		Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).Limit(0, limit).Build()).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, result)
}

func (s *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	result, err := s.cli.Do(ctx, s.cli.B().Zrangebyscore().Key(s.lastActivityIndexKey).
		Min("-inf").Max(fmt.Sprintf("%d", before.Unix())).Limit(0, limit).Build()).AsStrSlice()
	if err != nil {
		return nil, err
	}

	return s.loadSandboxesBySessionIDs(ctx, result)
}

func (s *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*types.SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = s.sessionKey(id)
	}

	results, err := s.cli.Do(ctx, s.cli.B().Mget().Key(keys...).Build()).AsStrSlice()
	if err != nil {
		return nil, err
	}

	sandboxes := make([]*types.SandboxInfo, 0, len(sessionIDs))
	for i, result := range results {
		if result == "" {
			klog.Warningf("session key not found for ID: %s", sessionIDs[i])
			continue
		}

		var info types.SandboxInfo
		if err := json.Unmarshal([]byte(result), &info); err != nil {
			klog.Warningf("failed to unmarshal sandbox info for ID %s: %v", sessionIDs[i], err)
			continue
		}
		sandboxes = append(sandboxes, &info)
	}

	return sandboxes, nil
}

func (s *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("sessionID is required")
	}

	key := s.sessionKey(sessionID)
	exists, err := s.cli.Do(ctx, s.cli.B().Exists().Key(key).Build()).AsInt64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	return s.cli.Do(ctx, s.cli.B().Zadd().Key(s.lastActivityIndexKey).
		ScoreMember().ScoreMember(float64(at.Unix()), sessionID).Build()).Error()
}

func (s *valkeyStore) Close() error {
	s.cli.Close()
	return nil
}

