func TestCreateSandboxRequest_Validate(t *testing.T) {
	tests := []struct {
		name    string
		req     CreateSandboxRequest
		wantErr bool
	}{
		{
			name: "valid AgentRuntime request",
			req: CreateSandboxRequest{
				Kind:      AgentRuntimeKind,
				Name:      "test-agent",
				Namespace: "default",
			},
			wantErr: false,
		},
		{
			name: "valid CodeInterpreter request",
			req: CreateSandboxRequest{
				Kind:      CodeInterpreterKind,
				Name:      "test-code",
				Namespace: "default",
			},
			wantErr: false,
		},
		{
			name: "missing namespace",
			req: CreateSandboxRequest{
				Kind: AgentRuntimeKind,
				Name: "test-agent",
			},
			wantErr: true,
		},
		{
			name: "missing name",
			req: CreateSandboxRequest{
				Kind:      AgentRuntimeKind,
				Namespace: "default",
			},
			wantErr: true,
		},
		{
			name: "invalid kind",
			req: CreateSandboxRequest{
				Kind:      "InvalidKind",
				Name:      "test",
				Namespace: "default",
			},
			wantErr: true,
		},
		{
			name:    "empty request",
			req:     CreateSandboxRequest{},
			wantErr: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			err := tt.req.Validate()
			if (err != nil) != tt.wantErr {
				t.Errorf("CreateSandboxRequest.Validate() error = %v, wantErr %v", err, tt.wantErr)
			}
		})
	}
}

