func TestNewSessionNotFoundError(t *testing.T) {
	sessionID := "test-session-123"
	err := NewSessionNotFoundError(sessionID)

	if err == nil {
		t.Fatal("expected error, got nil")
	}

	var statusErr *apierrors.StatusError
	if !errors.As(err, &statusErr) {
		t.Fatalf("expected StatusError, got %T", err)
	}

	status := statusErr.ErrStatus
	if status.Code != 404 {
		t.Errorf("expected status code 404, got %d", status.Code)
	}
	if status.Reason != metav1.StatusReasonNotFound {
		t.Errorf("expected status reason NotFound, got %s", status.Reason)
	}
}

