func TestIsPasswordNotRequired(t *testing.T) {
	tests := []struct {
		name     string
		envValue string
		expected bool
	}{
		{
			name:     "false string",
			envValue: "false",
			expected: true,
		},
		{
			name:     "FALSE uppercase",
			envValue: "FALSE",
			expected: true,
		},
		{
			name:     "False mixed case",
			envValue: "False",
			expected: true,
		},
		{
			name:     "true string",
			envValue: "true",
			expected: false,
		},
		{
			name:     "empty string",
			envValue: "",
			expected: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			t.Setenv("REDIS_PASSWORD_REQUIRED", tt.envValue)
			result := isPasswordNotRequired()
			if result != tt.expected {
				t.Errorf("isPasswordNotRequired() = %v, want %v", result, tt.expected)
			}
		})
	}
}

